"""
Convert 3D model from .obj format to .wrl with colors
"""

from __future__ import annotations

# Global imports
import logging
import re
import textwrap

# Local imports
from ..easyeda.parameters_easyeda import Ee3dModel
from .parameters_kicad_footprint import Ki3dModel, Ki3dModelBase

VRML_HEADER = """#VRML V2.0 utf8
# 3D model generated by easyeda2kicad.py (https://github.com/uPesy/easyeda2kicad.py)
"""


def get_materials(obj_data: str) -> dict[str, dict[str, str | list[str]]]:
    material_regex = "newmtl .*?endmtl"
    matchs = re.findall(pattern=material_regex, string=obj_data, flags=re.DOTALL)

    materials = {}
    for match in matchs:
        material = {}
        material_id = None
        for value in match.splitlines():
            if value.startswith("newmtl"):
                material_id = value.split()[1]
            elif value.startswith("Ka"):
                material["ambient_color"] = value.split()[1:]
            elif value.startswith("Kd"):
                material["diffuse_color"] = value.split()[1:]
            elif value.startswith("Ks"):
                material["specular_color"] = value.split()[1:]
            elif value.startswith("d"):
                # This isn't exactly the same as transparency, is dissolve
                # I.e. part C115366 (SW-TH_SPEF110100) has d=1, and isn't transparent
                material["transparency"] = value.split()[1]

        if material_id is not None:
            materials[material_id] = material
    return materials


def get_vertices(
    obj_data: str,
    offset_x: float = 0.0,
    offset_y: float = 0.0,
    offset_z: float = 0.0,
) -> list[str]:
    result = []
    for line in obj_data.splitlines():
        parts = line.split()
        if len(parts) < 4 or parts[0] != "v":
            continue
        x, y, z = float(parts[1]), float(parts[2]), float(parts[3])
        result.append(
            " ".join(
                [
                    str(round((x + offset_x) / 2.54, 4)),
                    str(round((y + offset_y) / 2.54, 4)),
                    str(round((z + offset_z) / 2.54, 4)),
                ]
            )
        )
    return result


def _get_obj_bbox(
    raw_obj: str,
) -> tuple[tuple[float, float], tuple[float, float], tuple[float, float]] | None:
    """Returns ((x_min, x_max), (y_min, y_max), (z_min, z_max)) or None if no vertices."""
    x_vals, y_vals, z_vals = [], [], []
    for line in raw_obj.splitlines():
        parts = line.split()
        if len(parts) < 4 or parts[0] != "v":
            continue
        x_vals.append(float(parts[1]))
        y_vals.append(float(parts[2]))
        z_vals.append(float(parts[3]))

    if not x_vals:
        return None

    return (
        (min(x_vals), max(x_vals)),
        (min(y_vals), max(y_vals)),
        (min(z_vals), max(z_vals)),
    )


def generate_wrl_model(model_3d: Ee3dModel, fp_type: str = "") -> Ki3dModel:
    if not model_3d.raw_obj:
        return Ki3dModel(
            translation=Ki3dModelBase(),
            rotation=Ki3dModelBase(),
            name=model_3d.name,
            raw_wrl=None,
        )

    materials = get_materials(obj_data=model_3d.raw_obj)

    # For SMD parts: center XY on (0,0) and shift Z so bottom sits at z=0
    offset_x, offset_y, offset_z = 0.0, 0.0, 0.0
    if fp_type == "smd":
        bbox = _get_obj_bbox(model_3d.raw_obj)
        if bbox:
            (x_min, x_max), (y_min, y_max), (z_min, _) = bbox
            offset_x = -(x_min + x_max) / 2.0
            offset_y = -(y_min + y_max) / 2.0
            offset_z = -z_min
        logging.debug(
            f"3D SMD centering offset: "
            f"X={offset_x:.2f} Y={offset_y:.2f} Z={offset_z:.2f}"
        )

    vertices = get_vertices(
        obj_data=model_3d.raw_obj,
        offset_x=offset_x,
        offset_y=offset_y,
        offset_z=offset_z,
    )

    raw_wrl = VRML_HEADER
    shapes = model_3d.raw_obj.split("usemtl")[1:]
    if not shapes:
        logging.warning(
            f"3D model '{model_3d.name}': OBJ has no 'usemtl' sections; no geometry exported"
        )
        return Ki3dModel(
            translation=Ki3dModelBase(),
            rotation=Ki3dModelBase(),
            name=model_3d.name,
            raw_wrl=None,
        )
    for shape in shapes:
        lines = shape.splitlines()
        material_name = lines[0].replace(" ", "")
        material = materials.get(material_name)
        if material is None:
            logging.warning(
                f"3D model material '{material_name}' not found, skipping shape"
            )
            continue
        index_counter = 0
        link_dict = {}
        coord_index = []
        points = []
        for line in lines[1:]:
            if line.strip() and line.split()[0] == "f":
                face = [int(tok.split("/")[0]) for tok in line.split()[1:]]
                face_index = []
                for index in face:
                    if index not in link_dict:
                        link_dict[index] = index_counter
                        face_index.append(str(index_counter))
                        points.append(vertices[index - 1])
                        index_counter += 1
                    else:
                        face_index.append(str(link_dict[index]))
                face_index.append("-1")
                coord_index.append(",".join(face_index) + ",")

        shape_str = textwrap.dedent(
            f"""
            Shape{{
                appearance Appearance {{
                    material  Material 	{{
                        diffuseColor {" ".join(material["diffuse_color"])}
                        specularColor {" ".join(material["specular_color"])}
                        ambientIntensity 0.2
                        transparency 0
                        shininess 0.5
                    }}
                }}
                geometry IndexedFaceSet {{
                    ccw TRUE
                    solid FALSE
                    coord DEF co Coordinate {{
                        point [
                            {(", ").join(points)}
                        ]
                    }}
                    coordIndex [
                        {"".join(coord_index)}
                    ]
                }}
            }}"""
        )

        raw_wrl += shape_str

    return Ki3dModel(
        translation=Ki3dModelBase(),
        rotation=Ki3dModelBase(),
        name=model_3d.name,
        raw_wrl=raw_wrl,
    )


def _log_obj_bbox(raw_obj: str) -> None:
    """Log the OBJ vertex bounding box at DEBUG level."""
    bbox = _get_obj_bbox(raw_obj)
    if not bbox:
        logging.debug("3D OBJ: no vertices found")
        return

    (x_min, x_max), (y_min, y_max), (z_min, z_max) = bbox
    logging.debug(
        "3D OBJ bbox: "
        f"X [{x_min:.6g} .. {x_max:.6g}] "
        f"Y [{y_min:.6g} .. {y_max:.6g}] "
        f"Z [{z_min:.6g} .. {z_max:.6g}]"
    )


class Exporter3dModelKicad:
    def __init__(self, model_3d: Ee3dModel | None, fp_type: str = ""):
        self.input = model_3d
        self.fp_type = fp_type
        if model_3d and model_3d.raw_obj:
            _log_obj_bbox(model_3d.raw_obj)
        self.output = (
            generate_wrl_model(model_3d=model_3d, fp_type=fp_type)
            if model_3d and model_3d.raw_obj
            else None
        )
        self.output_step = model_3d.step if model_3d else None

    def export(self, output_dir: str) -> None:
        """Write WRL and/or STEP files into *output_dir* (the .3dshapes folder)."""
        if self.output and self.output.raw_wrl:
            with open(
                file=f"{output_dir}/{self.output.name}.wrl",
                mode="w",
                encoding="utf-8",
            ) as my_lib:
                my_lib.write(self.output.raw_wrl)
        if self.output_step and self.output:
            with open(
                file=f"{output_dir}/{self.output.name}.step",
                mode="wb",
            ) as my_lib:
                my_lib.write(self.output_step)
